43	
44	// emittedOps accumulates the ops a single emit call produces. Built
45	// up across kind-specific helpers; rendered into OpsPerformed at the
46	// end of handleEmit.
47	type emittedOps struct {
48		ops []adapterkit.Op
49	}
50	
51	func (e *emittedOps) add(op adapterkit.Op) {
52		e.ops = append(e.ops, op)
53	}
54	
55	// records returns the OpRecord summary slice the v1 protocol carries
56	// in EmitResult.OpsPerformed. Content is built but discarded — the
57	// wire format only carries summaries.
58	func (e *emittedOps) records() []adapterkit.OpRecord {
59		out := make([]adapterkit.OpRecord, 0, len(e.ops))
60		for _, op := range e.ops {
61			out = append(out, adapterkit.OpRecord{Op: op.OpKind(), Path: op.OpPath()})
62		}
63		return out
64	}
65	
66	// handleEmit is the OnEmit handler the bundled adapter registers.
67	// Decodes the IR document, dispatches each node by kind, and returns
68	// the accumulated OpRecord summary.
69	//
70	// One-failed-node-fails-the-emit is the v1 behavior: if any node
71	// produces an error, the whole call returns that error and partially
72	// emitted ops are discarded. Per-node skip-with-warning is a Unit 8b
73	// extension.
74	//
75	// Context is checked between nodes so a runtime cancel during a
76	// large IR is honored without waiting for the full iteration.
77	func handleEmit(ctx context.Context, params adapterkit.EmitParams) (adapterkit.EmitResult, error) {
78		doc, err := decodeIRDocument(params.IR)
79		if err != nil {
80			return adapterkit.EmitResult{}, &adapterkit.Error{
81				Code:    adapterkit.CodeInvalidParams,
82				Message: fmt.Sprintf("claude: %s", err.Error()),
83			}
84		}
85	
86		// Detect duplicate (kind, id) pairs in the wire payload before
87		// emitting. The IR decoder enforces uniqueness on its own output
88		// but the wire shape can carry duplicates from a buggy or
89		// adversarial producer; emitting the same path twice would let
90		// the sync engine silently last-write-wins.
91		if err := rejectDuplicateNodes(doc.Nodes); err != nil {
92			return adapterkit.EmitResult{}, err
93		}
94	
95		emitted := &emittedOps{}
96	
97		// readmeEmitted dedups per-subdir mkdir+README pairs.
98		// sidecarEmitted dedups the .aienvs-managed sidecar (only ever
99		// written next to .mcp.json; one per emit regardless of how many
100		// mcp-server-entry nodes are present).
101		state := emitState{
102			readmeEmitted:   map[string]bool{},
103			sidecarEmitted:  false,
104			emittedFilePath: map[string]struct{}{},
105		}
106	
107		// Iterate in a deterministic order (sorted by kind, then id) so
108		// op output is stable across runs and easy to compare against
109		// fixtures. The IR decoder upstream already sorts the same way,
110		// but we re-sort defensively in case a malformed decoder ships
111		// nodes in arbitrary order.
112		slices.SortFunc(doc.Nodes, func(a, b irNode) int {
113			if c := cmp.Compare(a.Kind, b.Kind); c != 0 {
114				return c
115			}
116			return cmp.Compare(a.ID, b.ID)
117		})
118	
119		for _, node := range doc.Nodes {
120			if err := ctx.Err(); err != nil {
121				return adapterkit.EmitResult{}, &adapterkit.Error{
122					Code:    adapterkit.CodeInternalError,
123					Message: fmt.Sprintf("claude: emit cancelled: %s", err.Error()),
124				}
125			}
126			if !nodeTargetsClaude(node) {
127				// Node is targeted at a different adapter — silent skip.
128				continue
129			}
130			if err := dispatchNode(emitted, node, &state); err != nil {
131				return adapterkit.EmitResult{}, err
132			}
133		}
134	
135		return adapterkit.EmitResult{OpsPerformed: emitted.records()}, nil
136	}
137	
138	// emitState carries per-emit dedup tables. Threading one struct
139	// instead of multiple maps keeps dispatchNode's signature stable as
140	// new dedup keys appear.
141	//
142	// emittedFilePath records every workspace-relative path that's been
143	// emitted as a write_file in this call. When two ops would target
144	// the same path (duplicate skill assets, asset RelPath colliding
145	// with the reserved README.md inside a per-skill folder, etc.) the
146	// dispatcher fails closed instead of letting the sync engine
147	// last-write-wins.
148	type emitState struct {
149		readmeEmitted   map[string]bool
150		sidecarEmitted  bool
151		emittedFilePath map[string]struct{}
152	}
153	
154	// recordWritePath registers a write_file path in the per-emit dedup
155	// table. Returns an InvalidParams error when the path was already
156	// emitted earlier in this call. Callers should check before
157	// constructing the OpWriteFile so the error message can include
158	// node-level context.
159	func (s *emitState) recordWritePath(path string) error {
160		if _, exists := s.emittedFilePath[path]; exists {
161			return &adapterkit.Error{
162				Code:    adapterkit.CodeInvalidParams,
163				Message: fmt.Sprintf("claude: duplicate write_file path %q in single emit", path),
164			}
165		}
166		s.emittedFilePath[path] = struct{}{}
167		return nil
168	}
169	
170	// dispatchNode routes one IR node to its kind-specific emitter.
171	func dispatchNode(emitted *emittedOps, node irNode, state *emitState) error {
172		if !ir.IsValidID(node.ID) {
173			return &adapterkit.Error{
174				Code:    adapterkit.CodeInvalidParams,
175				Message: fmt.Sprintf("claude: invalid node id %q", node.ID),
176			}
177		}
178		switch ir.Kind(node.Kind) {
179		case ir.KindRule:
180			return emitRule(emitted, node, state)
181		case ir.KindCommand:
182			return emitCommand(emitted, node, state)
183		case ir.KindSkill:
184			return emitSkill(emitted, node, state)
185		case ir.KindMCPServerEntry:
186			return emitMCPServerEntry(emitted, node, state)
187		case ir.KindAgentsMD:
188			return emitAgentsMD(emitted, node)
189		case ir.KindPluginReference:
190			return emitPluginReferenceWarning(emitted, node)
191		default:
192			return &adapterkit.Error{
193				Code:    adapterkit.CodeInvalidParams,
194				Message: fmt.Sprintf("claude: unknown IR kind %q for node %q", node.Kind, node.ID),
195			}
196		}
197	}
198	
199	// decodeIRDocument unmarshals the EmitParams.IR raw message. Returns
200	// a wrapped error on parse failure so handleEmit can convert it to a
201	// JSON-RPC InvalidParams response.
202	func decodeIRDocument(raw json.RawMessage) (irDocument, error) {
203		if len(raw) == 0 {
204			return irDocument{}, nil
205		}
206		var doc irDocument
207		if err := json.Unmarshal(raw, &doc); err != nil {
208			return irDocument{}, fmt.Errorf("decode IR document: %w", err)
209		}
210		return doc, nil
211	}
212	
213	// nodeTargetsClaude reports whether the node's targets list either
214	// is empty (means "all adapters") or includes the claude adapter.
215	// IR-side validation guarantees the contained values are known
216	// adapter names; we don't re-validate here.
217	func nodeTargetsClaude(node irNode) bool {
218		if len(node.Targets) == 0 {
219			return true
220		}
221		for _, t := range node.Targets {
222			if t == adapterName {
223				return true
224			}
225		}
226		return false
227	}
228	
229	// rejectDuplicateNodes returns InvalidParams when the wire payload
230	// contains two or more nodes with the same (kind, id) pair. The
231	// fail-closed default avoids the silent last-write-wins behavior the
232	// sync engine would otherwise hit at write time.
233	func rejectDuplicateNodes(nodes []irNode) error {
234		seen := make(map[string]struct{}, len(nodes))
235		for _, n := range nodes {
236			key := n.Kind + "/" + n.ID
237			if _, dup := seen[key]; dup {
238				return &adapterkit.Error{
239					Code:    adapterkit.CodeInvalidParams,
240					Message: fmt.Sprintf("claude: duplicate node (kind=%q id=%q) in IR payload", n.Kind, n.ID),
241				}
242			}
243			seen[key] = struct{}{}
244		}
245		return nil
246	}
247	
248	// decodeBodyOrPassthrough turns a node or asset Body field into raw
249	// bytes. The wire shape allows two body encodings:
250	//   - JSON string (markdown bodies): `"# heading\n..."`
251	//   - Raw JSON value (json/toml kinds): `{"command":"node",...}`
252	//
253	// String-decode is tried first; if that fails the raw JSON value is
254	// validated and passed through unchanged.
255	func decodeBodyOrPassthrough(raw json.RawMessage) ([]byte, error) {
256		if len(raw) == 0 || string(raw) == "null" {
257			return nil, nil
258		}
259		var s string
260		if err := json.Unmarshal(raw, &s); err == nil {
261			return []byte(s), nil
262		}
263		var any any
264		if err := json.Unmarshal(raw, &any); err != nil {
265			return nil, fmt.Errorf("body must be a JSON string or valid JSON value: %w", err)
266		}
267		return raw, nil
268	}
269	
270	// wrapBodyErr converts a node-body decode error into the structured
271	// JSON-RPC error the caller returns.
272	func wrapBodyErr(node irNode, err error) error {
273		return &adapterkit.Error{
274			Code:    adapterkit.CodeInvalidParams,
275			Message: fmt.Sprintf("claude: node %q (%s) body: %s", node.ID, node.Kind, err.Error()),
276		}
277	}
278	
279	// wrapOpErr converts an op-construction error (typically the
280	// payload-too-large guard inside NewOpWriteFile) into the structured
281	// JSON-RPC error the caller returns.
282	func wrapOpErr(node irNode, err error) error {
283		return &adapterkit.Error{
284			Code:    adapterkit.CodeInvalidParams,
285			Message: fmt.Sprintf("claude: node %q (%s) op: %s", node.ID, node.Kind, err.Error()),
286		}
287	}
