package claude

import (
	"cmp"
	"context"
	"encoding/json"
	"fmt"
	"slices"

	"github.com/aienvs/aienvs/internal/ir"
	"github.com/aienvs/aienvs/pkg/adapterkit"
)

// irNode is the wire-side shape of one IR node delivered via
// EmitParams.IR. The adapter does not import internal/ir's Node
// directly because that type carries decoder-internal fields the
// wire payload doesn't include.
type irNode struct {
	ID         string          `json:"id"`
	Kind       string          `json:"kind"`
	Version    int             `json:"version,omitempty"`
	Required   bool            `json:"required,omitempty"`
	Targets    []string        `json:"targets,omitempty"`
	Provenance irProvenance    `json:"provenance,omitempty"`
	Body       json.RawMessage `json:"body,omitempty"`
	Assets     []irAsset       `json:"assets,omitempty"`
}

type irProvenance struct {
	Path    string `json:"path,omitempty"`
	BlobSHA string `json:"blob_sha,omitempty"`
}

type irAsset struct {
	RelPath    string          `json:"rel_path"`
	Provenance irProvenance    `json:"provenance,omitempty"`
	Content    json.RawMessage `json:"content,omitempty"`
}

type irDocument struct {
	Nodes []irNode `json:"nodes"`
}

// emittedOps accumulates the ops a single emit call produces. Built
// up across kind-specific helpers; rendered into OpsPerformed at the
// end of handleEmit.
type emittedOps struct {
	ops []adapterkit.Op
}

func (e *emittedOps) add(op adapterkit.Op) {
	e.ops = append(e.ops, op)
}

// records returns the OpRecord summary slice the v1 protocol carries
// in EmitResult.OpsPerformed. Content is built but discarded — the
// wire format only carries summaries.
func (e *emittedOps) records() []adapterkit.OpRecord {
	out := make([]adapterkit.OpRecord, 0, len(e.ops))
	for _, op := range e.ops {
		out = append(out, adapterkit.OpRecord{Op: op.OpKind(), Path: op.OpPath()})
	}
	return out
}

// handleEmit is the OnEmit handler the bundled adapter registers.
// Decodes the IR document, dispatches each node by kind, and returns
// the accumulated OpRecord summary.
//
// One-failed-node-fails-the-emit is the v1 behavior: if any node
// produces an error, the whole call returns that error and partially
// emitted ops are discarded. Per-node skip-with-warning is a Unit 8b
// extension.
//
// Context is checked between nodes so a runtime cancel during a
// large IR is honored without waiting for the full iteration.
func handleEmit(ctx context.Context, params adapterkit.EmitParams) (adapterkit.EmitResult, error) {
	doc, err := decodeIRDocument(params.IR)
	if err != nil {
		return adapterkit.EmitResult{}, &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("claude: %s", err.Error()),
		}
	}

	// Detect duplicate (kind, id) pairs in the wire payload before
	// emitting. The IR decoder enforces uniqueness on its own output
	// but the wire shape can carry duplicates from a buggy or
	// adversarial producer; emitting the same path twice would let
	// the sync engine silently last-write-wins.
	if err := rejectDuplicateNodes(doc.Nodes); err != nil {
		return adapterkit.EmitResult{}, err
	}

	emitted := &emittedOps{}

	// readmeEmitted dedups per-subdir mkdir+README pairs.
	// sidecarEmitted dedups the .aienvs-managed sidecar (only ever
	// written next to .mcp.json; one per emit regardless of how many
	// mcp-server-entry nodes are present).
	state := emitState{
		readmeEmitted:   map[string]bool{},
		sidecarEmitted:  false,
		emittedFilePath: map[string]struct{}{},
	}

	// Iterate in a deterministic order (sorted by kind, then id) so
	// op output is stable across runs and easy to compare against
	// fixtures. The IR decoder upstream already sorts the same way,
	// but we re-sort defensively in case a malformed decoder ships
	// nodes in arbitrary order.
	slices.SortFunc(doc.Nodes, func(a, b irNode) int {
		if c := cmp.Compare(a.Kind, b.Kind); c != 0 {
			return c
		}
		return cmp.Compare(a.ID, b.ID)
	})

	for _, node := range doc.Nodes {
		if err := ctx.Err(); err != nil {
			return adapterkit.EmitResult{}, &adapterkit.Error{
				Code:    adapterkit.CodeInternalError,
				Message: fmt.Sprintf("claude: emit cancelled: %s", err.Error()),
			}
		}
		if !nodeTargetsClaude(node) {
			// Node is targeted at a different adapter — silent skip.
			continue
		}
		if err := dispatchNode(emitted, node, &state); err != nil {
			return adapterkit.EmitResult{}, err
		}
	}

	return adapterkit.EmitResult{OpsPerformed: emitted.records()}, nil
}

// emitState carries per-emit dedup tables. Threading one struct
// instead of multiple maps keeps dispatchNode's signature stable as
// new dedup keys appear.
//
// emittedFilePath records every workspace-relative path that's been
// emitted as a write_file in this call. When two ops would target
// the same path (duplicate skill assets, asset RelPath colliding
// with the reserved README.md inside a per-skill folder, etc.) the
// dispatcher fails closed instead of letting the sync engine
// last-write-wins.
type emitState struct {
	readmeEmitted   map[string]bool
	sidecarEmitted  bool
	emittedFilePath map[string]struct{}
}

// recordWritePath registers a write_file path in the per-emit dedup
// table. Returns an InvalidParams error when the path was already
// emitted earlier in this call. Callers should check before
// constructing the OpWriteFile so the error message can include
// node-level context.
func (s *emitState) recordWritePath(path string) error {
	if _, exists := s.emittedFilePath[path]; exists {
		return &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("claude: duplicate write_file path %q in single emit", path),
		}
	}
	s.emittedFilePath[path] = struct{}{}
	return nil
}

// dispatchNode routes one IR node to its kind-specific emitter.
func dispatchNode(emitted *emittedOps, node irNode, state *emitState) error {
	if !ir.IsValidID(node.ID) {
		return &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("claude: invalid node id %q", node.ID),
		}
	}
	switch ir.Kind(node.Kind) {
	case ir.KindRule:
		return emitRule(emitted, node, state)
	case ir.KindCommand:
		return emitCommand(emitted, node, state)
	case ir.KindSkill:
		return emitSkill(emitted, node, state)
	case ir.KindMCPServerEntry:
		return emitMCPServerEntry(emitted, node, state)
	case ir.KindAgentsMD:
		return emitAgentsMD(emitted, node)
	case ir.KindPluginReference:
		return emitPluginReferenceWarning(emitted, node)
	default:
		return &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("claude: unknown IR kind %q for node %q", node.Kind, node.ID),
		}
	}
}

// decodeIRDocument unmarshals the EmitParams.IR raw message. Returns
// a wrapped error on parse failure so handleEmit can convert it to a
// JSON-RPC InvalidParams response.
func decodeIRDocument(raw json.RawMessage) (irDocument, error) {
	if len(raw) == 0 {
		return irDocument{}, nil
	}
	var doc irDocument
	if err := json.Unmarshal(raw, &doc); err != nil {
		return irDocument{}, fmt.Errorf("decode IR document: %w", err)
	}
	return doc, nil
}

// nodeTargetsClaude reports whether the node's targets list either
// is empty (means "all adapters") or includes the claude adapter.
// IR-side validation guarantees the contained values are known
// adapter names; we don't re-validate here.
func nodeTargetsClaude(node irNode) bool {
	if len(node.Targets) == 0 {
		return true
	}
	for _, t := range node.Targets {
		if t == adapterName {
			return true
		}
	}
	return false
}

// rejectDuplicateNodes returns InvalidParams when the wire payload
// contains two or more nodes with the same (kind, id) pair. The
// fail-closed default avoids the silent last-write-wins behavior the
// sync engine would otherwise hit at write time.
func rejectDuplicateNodes(nodes []irNode) error {
	seen := make(map[string]struct{}, len(nodes))
	for _, n := range nodes {
		key := n.Kind + "/" + n.ID
		if _, dup := seen[key]; dup {
			return &adapterkit.Error{
				Code:    adapterkit.CodeInvalidParams,
				Message: fmt.Sprintf("claude: duplicate node (kind=%q id=%q) in IR payload", n.Kind, n.ID),
			}
		}
		seen[key] = struct{}{}
	}
	return nil
}

// decodeBodyOrPassthrough turns a node or asset Body field into raw
// bytes. The wire shape allows two body encodings:
//   - JSON string (markdown bodies): `"# heading\n..."`
//   - Raw JSON value (json/toml kinds): `{"command":"node",...}`
//
// String-decode is tried first; if that fails the raw JSON value is
// validated and passed through unchanged.
func decodeBodyOrPassthrough(raw json.RawMessage) ([]byte, error) {
	if len(raw) == 0 || string(raw) == "null" {
		return nil, nil
	}
	var s string
	if err := json.Unmarshal(raw, &s); err == nil {
		return []byte(s), nil
	}
	var any any
	if err := json.Unmarshal(raw, &any); err != nil {
		return nil, fmt.Errorf("body must be a JSON string or valid JSON value: %w", err)
	}
	return raw, nil
}

// wrapBodyErr converts a node-body decode error into the structured
// JSON-RPC error the caller returns.
func wrapBodyErr(node irNode, err error) error {
	return &adapterkit.Error{
		Code:    adapterkit.CodeInvalidParams,
		Message: fmt.Sprintf("claude: node %q (%s) body: %s", node.ID, node.Kind, err.Error()),
	}
}

// wrapOpErr converts an op-construction error (typically the
// payload-too-large guard inside NewOpWriteFile) into the structured
// JSON-RPC error the caller returns.
func wrapOpErr(node irNode, err error) error {
	return &adapterkit.Error{
		Code:    adapterkit.CodeInvalidParams,
		Message: fmt.Sprintf("claude: node %q (%s) op: %s", node.ID, node.Kind, err.Error()),
	}
}

package claude

import (
	_ "embed"
	"fmt"

	"github.com/goccy/go-yaml"

	"github.com/aienvs/aienvs/internal/capmatrix"
	"github.com/aienvs/aienvs/internal/ir"
	"github.com/aienvs/aienvs/pkg/adapterkit"
)

//go:embed capabilities.yaml
var capabilitiesYAML []byte

// declarationFile is the parsed shape of capabilities.yaml. It is
// intentionally narrower than adapter.AdapterManifest so the file
// stays a per-adapter declaration and not an arbitrary manifest
// override.
type declarationFile struct {
	Name            string                            `yaml:"name"`
	Version         string                            `yaml:"version"`
	ContractVersion string                            `yaml:"contract_version"`
	ReservedPrefix  string                            `yaml:"reserved_prefix"`
	ConceptKinds    map[string]conceptKindDeclaration `yaml:"concept_kinds"`
}

type conceptKindDeclaration struct {
	Status capmatrix.CapabilityStatus `yaml:"status"`
	Note   string                     `yaml:"note,omitempty"`
}

// conceptKinds is the in-code mirror of capabilities.yaml. The unit
// test asserts the two are kept in sync; if you add a kind here,
// add it there (and vice versa).
//
// The status values use capmatrix's vocabulary; the wire conversion
// happens in capabilitiesForWire.
var conceptKinds = map[ir.Kind]capmatrix.CapabilityStatus{
	ir.KindAgentsMD:        capmatrix.Supported,
	ir.KindRule:            capmatrix.Supported,
	ir.KindSkill:           capmatrix.Supported,
	ir.KindCommand:         capmatrix.Supported,
	ir.KindMCPServerEntry:  capmatrix.Supported,
	ir.KindPluginReference: capmatrix.Unsupported,
}

// capabilitiesForWire returns the adapterkit.Capabilities the adapter
// echoes in its initialize response. WriteToolOwned is true because
// the claude adapter emits write_tool_owned ops for .mcp.json and
// CLAUDE.md.
func capabilitiesForWire() adapterkit.Capabilities {
	builder := adapterkit.NewCapabilities().WithWriteToolOwned(true)
	for kind, status := range conceptKinds {
		switch status {
		case capmatrix.Supported:
			builder.Supports(string(kind))
		case capmatrix.Partial:
			builder.Partial(string(kind))
		case capmatrix.Unsupported:
			builder.Unsupported(string(kind))
		}
	}
	return builder.Build()
}

// declaredOutputs returns the list the adapter advertises in its
// initialize response. The runtime path-safety gate
// (internal/adapter/runtime.go pathInDeclaredOutputs) accepts an
// emitted op only when its path falls inside one of these declared
// outputs.
func declaredOutputs() []adapterkit.DeclaredOutput {
	mcpPointer := "/mcpServers"
	claudeMDSection := "aienvs"
	return []adapterkit.DeclaredOutput{
		{Path: ".claude/rules/aienvs", Mode: adapterkit.OutputModeOwnedSubdir},
		{Path: ".claude/commands/aienvs", Mode: adapterkit.OutputModeOwnedSubdir},
		{Path: ".claude/skills", Mode: adapterkit.OutputModeOwnedSubdir},
		{Path: ".mcp.json", Mode: adapterkit.OutputModeToolOwnedEntry, JSONPointer: &mcpPointer},
		{Path: "CLAUDE.md", Mode: adapterkit.OutputModeToolOwnedEntry, SectionID: &claudeMDSection},
		// The strict-JSON sidecar marker (.aienvs-managed) is written
		// next to .mcp.json at workspace root. Declared as
		// owned-subdir on "." would over-broadly authorize the whole
		// workspace, so we declare the sidecar file by exact path.
		{Path: ".aienvs-managed", Mode: adapterkit.OutputModeOwnedSubdir},
	}
}

// parseCapabilitiesYAML decodes the embedded YAML. Used by the parity
// test and by callers that want the human-readable note bodies.
func parseCapabilitiesYAML(src []byte) (declarationFile, error) {
	var d declarationFile
	if err := yaml.UnmarshalWithOptions(
		src,
		&d,
		yaml.DisallowUnknownField(),
		yaml.AllowFieldPrefixes("x-"),
	); err != nil {
		return declarationFile{}, fmt.Errorf("claude: parse capabilities.yaml: %s", yaml.FormatError(err, false, true))
	}
	return d, nil
}

// loadDeclaration parses the embedded capabilities.yaml and returns
// the result. Cached at package level if it ever becomes a hot path;
// for now the call sites are test-only and one-off.
func loadDeclaration() (declarationFile, error) {
	return parseCapabilitiesYAML(capabilitiesYAML)
}

// Package claude implements the bundled aienvs adapter for Claude Code.
//
// The adapter consumes IR v1 nodes and emits the v1 op vocabulary
// (write_file, write_tool_owned, mkdir, delete, warning) for Claude
// Code's actual on-disk layout:
//
//   - rule    -> .claude/rules/aienvs/<id>.md
//   - command -> .claude/commands/aienvs/<id>.md
//   - skill   -> .claude/skills/aienvs-<id>/SKILL.md plus assets
//   - mcp-server-entry -> .mcp.json (workspace root) via write_tool_owned
//   - agents-md (companion overlay) -> CLAUDE.md (workspace root)
//   - plugin-reference -> warning, unsupported by design
//
// Bundled() returns an *adapter.BundledAdapter ready for the runtime
// to spawn over an in-process pipe; nothing else in this package is
// part of the public surface.
package claude

import (
	"context"
	"fmt"
	"io"

	"github.com/aienvs/aienvs/internal/adapter"
	"github.com/aienvs/aienvs/pkg/adapterkit"
)

const (
	adapterName    = "claude"
	adapterVersion = "0.1"
	reservedPrefix = ".claude"
)

// Bundled returns the adapter.BundledAdapter for the claude target.
// The runtime registers it via adapter.DiscoverOptions.Bundled.
func Bundled() *adapter.BundledAdapter {
	return &adapter.BundledAdapter{
		Manifest: adapter.AdapterManifest{
			Name:            adapterName,
			Version:         adapterVersion,
			ContractVersion: adapter.ContractVersionV1,
			ReservedPrefix:  reservedPrefix,
			// Bundled adapters are spawned in-process via Run; the
			// Command slice is required by the shared manifest
			// validator (validateAdapterManifest in
			// internal/adapter/discover.go) but never executed for
			// SourceBundled — the runtime takes the Run path. The
			// placeholder name is recorded for diagnostics only.
			Command: []string{"aienvs-adapter-claude-bundled"},
		},
		Run: run,
	}
}

// run is the in-process entry point invoked by InprocTransport. It
// constructs an adapterkit.Server bound to the supplied pipes, wires
// up the lifecycle handlers, and serves until context is cancelled
// or the runtime sends shutdown.
func run(ctx context.Context, stdin io.Reader, stdout io.Writer) error {
	server := adapterkit.NewServer(adapterkit.ServerOptions{
		Name:    adapterName,
		Version: adapterVersion,
		Stdin:   stdin,
		Stdout:  stdout,
		// stderr defaults to os.Stderr; bundled in-process adapters
		// share the parent process so this routes diagnostics to the
		// CLI's own stderr, which is the documented place for them.
		// Getenv defaults to os.Getenv; bundled adapters skip the
		// magic-cookie check (the runtime sets cookie="" for bundled,
		// see internal/adapter/runtime.go Initialize), so the env-var
		// read still happens but the runtime ignores any echoed
		// cookie value.
		//
		// We supply a constant 32-hex string for the env-var so the
		// SDK's startup magic-cookie format check passes; the runtime
		// ignores the echoed value for bundled adapters.
		Getenv: bundledGetenv,
	})

	server.OnInitialize(func(_ context.Context, _ adapterkit.InitializeParams) (adapterkit.InitializeResult, error) {
		return adapterkit.InitializeResult{
			Capabilities:    capabilitiesForWire(),
			DeclaredOutputs: declaredOutputs(),
		}, nil
	})

	server.OnEmit(handleEmit)

	if err := server.Run(ctx); err != nil {
		return fmt.Errorf("claude bundled adapter: %w", err)
	}
	return nil
}

// bundledCookie is a 32-hex placeholder sent through the adapterkit
// Server's cookie format check. Bundled adapters skip cookie
// validation at the runtime layer (see internal/adapter/runtime.go
// Initialize: cookie validation is gated on Source != SourceBundled),
// so the value is opaque to the runtime — only the SDK's "format
// must be 32 hex" check observes it.
const bundledCookie = "00000000000000000000000000000000"

func bundledGetenv(name string) string {
	if name == adapterkit.CookieEnvVar {
		return bundledCookie
	}
	return ""
}

// handleEmit lives in emit.go.

package claude

import (
	"fmt"
	"strings"

	"github.com/aienvs/aienvs/internal/ir"
)

// managedHeaderTemplate is the canonical "do not edit" banner the
// claude adapter prepends to every owned markdown file. The
// {source-url} and {short-sha} placeholders are filled in by the
// sync engine (Unit 13) once it plumbs IR-decode context through
// EmitParams._meta. v1 ships the placeholder so the line shape is
// stable from day one.
//
// Trailing blank line keeps a one-line gap between the header and
// user-visible content; without it the body's first heading would
// fold into the comment block on some markdown renderers.
const managedHeaderTemplate = "<!-- Managed by aienvs — do not edit. Source: {source-url}@{short-sha}. Regenerate: aienvs sync -->\n\n"

// jsonSidecarBody is the body for the .aienvs-managed sidecar marker
// the claude adapter writes next to .mcp.json. JSON has no comment
// syntax, so the sidecar advertises ownership instead of editing
// the JSON file with a comment.
//
// The body is intentionally short and human-readable; it is not
// machine-parsed by anything in v1.
const jsonSidecarBody = `Managed by aienvs.

The sibling .mcp.json file contains entries owned by aienvs under
the /mcpServers/aienvs_<id> JSON pointers. Other entries are
preserved across syncs.

To remove aienvs-managed entries: aienvs unmanage claude
`

// markdownHeader returns the managed-file banner used at the top of
// every owned markdown file (rules, commands, skills). Content is
// constant in v1; future versions may inline real source URL +
// short SHA.
func markdownHeader() []byte {
	return []byte(managedHeaderTemplate)
}

// jsonSidecarMarker returns the body for the .aienvs-managed sidecar
// marker placed next to strict-JSON tool-owned files (currently just
// .mcp.json). See managedHeaderTemplate doc for why JSON gets a
// sidecar instead of an inline comment.
func jsonSidecarMarker() []byte {
	return []byte(jsonSidecarBody)
}

// sectionMarkerBegin returns the opening marker for a managed section
// inside a tool-owned markdown file (currently just CLAUDE.md). The
// marker is HTML-comment shaped so any markdown renderer treats it
// as invisible.
//
// id MUST satisfy the IR id grammar; an invalid id is a programming
// error inside the adapter (the IR decoder rejects bad ids upstream)
// and panics here so the failure surfaces immediately rather than
// silently corrupting CLAUDE.md.
func sectionMarkerBegin(id string) []byte {
	mustValidID(id)
	return []byte("<!-- aienvs:begin id=" + id + " -->")
}

// sectionMarkerEnd returns the closing marker. See sectionMarkerBegin
// for the id-validation contract.
func sectionMarkerEnd(id string) []byte {
	mustValidID(id)
	return []byte("<!-- aienvs:end id=" + id + " -->")
}

// wrapManagedSection wraps body bytes between the begin/end markers
// for the supplied id and returns the full slice ready for a
// write_tool_owned op. A trailing newline after the end marker keeps
// the merged file POSIX-clean if it is the last entry.
func wrapManagedSection(id string, body []byte) []byte {
	begin := sectionMarkerBegin(id)
	end := sectionMarkerEnd(id)
	out := make([]byte, 0, len(begin)+len(body)+len(end)+3)
	out = append(out, begin...)
	out = append(out, '\n')
	out = append(out, body...)
	if len(body) == 0 || body[len(body)-1] != '\n' {
		out = append(out, '\n')
	}
	out = append(out, end...)
	out = append(out, '\n')
	return out
}

// readmeForSubdir returns the README.md body the claude adapter
// emits into each reserved subdirectory. The README explains
// ownership and the exit path so a human stumbling into
// .claude/rules/aienvs/README.md knows it isn't user content.
//
// subdirLabel is the relative path used inside the body for clarity
// (e.g., ".claude/rules/aienvs"); pass the same string used in the
// declared output.
func readmeForSubdir(subdirLabel string) []byte {
	subdirLabel = strings.TrimSpace(subdirLabel)
	if subdirLabel == "" {
		// Defensive default. Empty subdirLabel is a programmer error;
		// an empty README is less harmful than a panic during a sync
		// that's already trying to recover.
		subdirLabel = "(unknown subdirectory)"
	}
	return fmt.Appendf(nil,
		"# Managed by aienvs\n\n"+
			"Files inside `%s/` are owned by the aienvs `claude` adapter.\n"+
			"Editing them by hand is detected as drift on the next sync\n"+
			"and the changes are overwritten.\n\n"+
			"To remove every aienvs-owned file in this directory and\n"+
			"unbind it from the workspace, run:\n\n"+
			"    aienvs unmanage claude\n",
		subdirLabel,
	)
}

// mustValidID panics with a programmer-targeted message when id
// does not satisfy the IR id grammar. The IR decoder catches user
// inputs upstream; this guard is for adapter bugs.
func mustValidID(id string) {
	if !ir.IsValidID(id) {
		panic(fmt.Sprintf("claude: invalid id %q reached marker construction (IR decoder should have rejected it upstream)", id))
	}
}

package claude

import (
	"bytes"
	"encoding/json"
	"fmt"

	"github.com/aienvs/aienvs/pkg/adapterkit"
)

const (
	mcpJSONPath        = ".mcp.json"
	mcpJSONPointerBase = "/mcpServers/aienvs_"
	claudeMDPath       = "CLAUDE.md"
	claudeMDSidecar    = ".aienvs-managed"
	sectionIDPrefix    = "aienvs:"
)

// markerOpenBytes is the literal HTML-comment opener every aienvs
// section marker uses. Body content for an agents-md node is rejected
// when it contains this byte sequence: a hostile body could otherwise
// inject a fake end-marker followed by a fake begin-marker, splitting
// the managed section in CLAUDE.md and confusing the merge step.
var markerOpenBytes = []byte("<!-- aienvs:")

// emitMCPServerEntry emits one write_tool_owned op into .mcp.json
// at /mcpServers/aienvs_<id>, plus a sidecar .aienvs-managed marker
// (deduplicated per emit) that advertises ownership next to the
// strict-JSON file.
//
// The body is required to parse as a JSON object. A scalar, array,
// or boolean body would corrupt the merged .mcp.json: Claude Code
// expects /mcpServers/<key> to map to an object with command/args
// fields, and storing a non-object value silently breaks every MCP
// load for the workspace.
//
// Validation is two-stage:
//  1. json.Valid — proves the bytes parse, catching string-encoded
//     bodies like "{" that look object-shaped at the first byte but
//     are actually unterminated JSON.
//  2. isJSONObject — proves the top-level structure is `{...}` and
//     not a number/array/bool/null that json.Valid alone would
//     accept.
func emitMCPServerEntry(emitted *emittedOps, node irNode, state *emitState) error {
	body, err := decodeBodyOrPassthrough(node.Body)
	if err != nil {
		return wrapBodyErr(node, err)
	}
	if !json.Valid(body) {
		return &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("claude: mcp-server-entry %q body is not valid JSON; refusing to corrupt .mcp.json", node.ID),
		}
	}
	if !isJSONObject(body) {
		return &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("claude: mcp-server-entry %q body must be a JSON object (got non-object)", node.ID),
		}
	}

	emitted.add(adapterkit.OpWriteToolOwned{
		Path:    mcpJSONPath,
		Kind:    adapterkit.ToolOwnedKindJSONPointer,
		Locator: mcpJSONPointerBase + node.ID,
		Content: body,
	})

	if !state.sidecarEmitted {
		state.sidecarEmitted = true
		sidecar, err := adapterkit.NewOpWriteFile(claudeMDSidecar, 0o644, jsonSidecarMarker())
		if err != nil {
			return wrapOpErr(node, err)
		}
		emitted.add(sidecar)
	}
	return nil
}

// emitAgentsMD writes the agents-md companion overlay into
// CLAUDE.md (workspace root) as a managed section between
// <!-- aienvs:begin id=<id> --> and <!-- aienvs:end id=<id> -->
// markers. CLAUDE.md is tool-owned by Claude Code; user content
// outside the managed section is preserved by the merge step
// (Unit 12a).
//
// The body is rejected when it contains the aienvs marker opener.
// Without this guard a body containing `<!-- aienvs:end id=other -->`
// could break out of its own section or forge another section
// entirely, leaving the merged CLAUDE.md with conflicting markers
// the merge step has no way to resolve safely.
//
// No managed-file header is added inside the section: the begin/end
// markers serve as the equivalent ownership advertisement, and a
// header inside a user-owned markdown file would be visually noisy.
func emitAgentsMD(emitted *emittedOps, node irNode) error {
	body, err := decodeBodyOrPassthrough(node.Body)
	if err != nil {
		return wrapBodyErr(node, err)
	}
	if bytes.Contains(body, markerOpenBytes) {
		return &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("claude: agents-md %q body contains aienvs marker syntax (%q); refusing to corrupt CLAUDE.md", node.ID, string(markerOpenBytes)),
		}
	}
	wrapped := wrapManagedSection(node.ID, body)

	emitted.add(adapterkit.OpWriteToolOwned{
		Path:    claudeMDPath,
		Kind:    adapterkit.ToolOwnedKindMarkdownSection,
		Locator: sectionIDPrefix + node.ID,
		Content: wrapped,
	})
	return nil
}

// emitPluginReferenceWarning surfaces the unsupported declaration
// for a plugin-reference node. Claude Code does not load
// project-level plugin registries, so the adapter declines and
// surfaces a degradation warning the sync engine will report.
//
// No write_file is emitted. The runtime's capability-lied check
// (internal/adapter/runtime.go) only fires for kinds the adapter
// declared as `supported`, so emitting a warning-only result here
// is safe — plugin-reference is declared `unsupported` in
// capabilities.yaml.
func emitPluginReferenceWarning(emitted *emittedOps, node irNode) error {
	emitted.add(adapterkit.OpWarning{
		ConceptID: node.ID,
		Status:    adapterkit.WarningStatusDegraded,
		Note:      "Claude Code does not load project-level plugin-reference registries; install plugins via Claude Code's own plugin command",
	})
	return nil
}

// isJSONObject reports whether body is a JSON object (`{...}`),
// not a scalar, array, or null. Assumes the caller already verified
// the bytes are valid JSON via decodeBodyOrPassthrough; the check
// here is purely structural — first non-whitespace byte must be `{`.
func isJSONObject(body []byte) bool {
	for _, b := range body {
		switch b {
		case ' ', '\t', '\n', '\r':
			continue
		case '{':
			return true
		default:
			return false
		}
	}
	return false
}

