106	// The skill folder gets no README.md: a per-skill README would clash
107	// with skill-discovery semantics, and the parent .claude/skills can
108	// hold user skills that we don't own.
109	func emitSkill(emitted *emittedOps, node irNode, state *emitState) error {
110		body, err := decodeBodyOrPassthrough(node.Body)
111		if err != nil {
112			return wrapBodyErr(node, err)
113		}
114	
115		skillDir := skillsParent + "/" + skillPrefix + node.ID
116		emitted.add(adapterkit.OpMkdir{Path: skillDir, Mode: 0o755})
117	
118		skillPath := skillDir + "/" + skillEntryFile
119		if err := state.recordWritePath(skillPath); err != nil {
120			return err
121		}
122		wf, err := adapterkit.NewOpWriteFile(skillPath, 0o644, prependHeader(body))
123		if err != nil {
124			return wrapOpErr(node, err)
125		}
126		emitted.add(wf)
127	
128		assets := slices.Clone(node.Assets)
129		slices.SortFunc(assets, func(a, b irAsset) int { return cmp.Compare(a.RelPath, b.RelPath) })
130	
131		for _, a := range assets {
132			if err := validateAssetRelPath(node.ID, a.RelPath); err != nil {
133				return err
134			}
135			assetPath := skillDir + "/" + a.RelPath
136			if err := state.recordWritePath(assetPath); err != nil {
137				return &adapterkit.Error{
138					Code:    adapterkit.CodeInvalidParams,
139					Message: fmt.Sprintf("claude: skill %q asset %q collides with another emitted path", node.ID, a.RelPath),
140				}
141			}
142			assetBody, err := decodeBodyOrPassthrough(a.Content)
143			if err != nil {
144				return &adapterkit.Error{
145					Code:    adapterkit.CodeInvalidParams,
146					Message: fmt.Sprintf("claude: skill %q asset %q body: %s", node.ID, a.RelPath, err.Error()),
147				}
148			}
149			op, err := adapterkit.NewOpWriteFile(assetPath, 0o644, assetBody)
150			if err != nil {
151				return &adapterkit.Error{
152					Code:    adapterkit.CodeInvalidParams,
153					Message: fmt.Sprintf("claude: skill %q asset %q: %s", node.ID, a.RelPath, err.Error()),
154				}
155			}
156			emitted.add(op)
157		}
158		return nil
159	}
160	
161	// validateAssetRelPath rejects RelPath shapes that would let a skill
162	// asset escape its own folder, target a directory rather than a file,
163	// or collide with the reserved SKILL.md entrypoint. Defense in depth:
164	// the runtime's declared-outputs gate catches workspace escapes but
165	// does not enforce per-skill containment, so the adapter is the only
166	// line of defense for this class of issue.
167	func validateAssetRelPath(skillID, relPath string) error {
168		if relPath == "" {
169			return &adapterkit.Error{
170				Code:    adapterkit.CodeInvalidParams,
171				Message: fmt.Sprintf("claude: skill %q has asset with empty rel_path", skillID),
172			}
173		}
174		// Reject absolute paths (POSIX or Windows-volume) and backslash —
175		// wire-protocol paths are forward-slash only.
176		if strings.HasPrefix(relPath, "/") || strings.ContainsRune(relPath, '\\') {
177			return &adapterkit.Error{
178				Code:    adapterkit.CodeInvalidParams,
179				Message: fmt.Sprintf("claude: skill %q asset %q must be a forward-slash workspace-relative path", skillID, relPath),
180			}
181		}
182		// path.Clean normalizes "./", duplicate "//", and "..". If the
183		// cleaned form differs from the input, or starts with "..", or
184		// contains a "/.." segment, the path tries to escape the skill
185		// folder. Reject.
186		cleaned := path.Clean(relPath)
187		if cleaned == ".." || strings.HasPrefix(cleaned, "../") || strings.Contains(cleaned, "/../") {
188			return &adapterkit.Error{
189				Code:    adapterkit.CodeInvalidParams,
190				Message: fmt.Sprintf("claude: skill %q asset %q escapes skill folder via ..", skillID, relPath),
191			}
192		}
193		if cleaned != relPath {
194			return &adapterkit.Error{
195				Code:    adapterkit.CodeInvalidParams,
196				Message: fmt.Sprintf("claude: skill %q asset %q is not in canonical form (cleaned: %q)", skillID, relPath, cleaned),
197			}
198		}
199		// Reject directory-only paths. path.Clean(".") == "." which would
200		// produce an op path like ".claude/skills/aienvs-x/." pointing at
201		// the skill directory itself, not a file. Reject before the sync
202		// engine has to handle it.
203		if cleaned == "." {
204			return &adapterkit.Error{
205				Code:    adapterkit.CodeInvalidParams,
206				Message: fmt.Sprintf("claude: skill %q asset rel_path must name a file, not the skill directory itself (got %q)", skillID, relPath),
207			}
208		}
209		// Reject the reserved SKILL.md entrypoint path. SKILL.md is owned
210		// by the skill body emission above; an asset sharing that name
211		// would silently overwrite the skill body itself.
212		if cleaned == skillEntryFile {
213			return &adapterkit.Error{
214				Code:    adapterkit.CodeInvalidParams,
215				Message: fmt.Sprintf("claude: skill %q asset rel_path %q collides with the reserved SKILL.md entrypoint", skillID, relPath),
216			}
217		}
218		return nil
219	}
220	
221	// ensureSubdir adds the per-emit mkdir + README pair for a reserved
222	// subdirectory once per emit call. Subsequent calls are no-ops.
223	//
224	// Returns InvalidParams if a node ID has already taken the README
225	// path inside this subdir (e.g., a rule node literally named "README"
226	// — its emitted path would be .../aienvs/README.md).
227	func ensureSubdir(emitted *emittedOps, subdir string, state *emitState) error {
228		if state.readmeEmitted[subdir] {
229			return nil
230		}
231		state.readmeEmitted[subdir] = true
232		emitted.add(adapterkit.OpMkdir{Path: subdir, Mode: 0o755})
233		readmePath := subdir + "/README.md"
234		if err := state.recordWritePath(readmePath); err != nil {
235			return err
236		}
237		wf, err := adapterkit.NewOpWriteFile(readmePath, 0o644, readmeForSubdir(subdir))
238		if err != nil {
239			// readmeForSubdir returns a small fixed body; the only way
240			// NewOpWriteFile can fail is the payload-too-large guard,
241			// which is unreachable here. Panic surfaces the bug.
242			panic(fmt.Sprintf("claude: building README for %s: %v", subdir, err))
243		}
244		emitted.add(wf)
245		return nil
246	}
247	
248	// prependHeader inserts the managed-file header before the body.
249	func prependHeader(body []byte) []byte {
250		header := markdownHeader()
251		out := make([]byte, 0, len(header)+len(body))
252		out = append(out, header...)
253		out = append(out, body...)
254		return out
255	}
256	
257	// hasPathsFrontmatter reports whether body opens with a YAML
258	// frontmatter block whose first content line is `paths:`. Best-
259	// effort: a body with frontmatter that places `paths:` after other
260	// fields is missed. v1 ships the conservative check; full
261	// frontmatter exposure is a v1.x change to the IR.
262	//
263	// Accepts both `---\n` and `---\r\n` separators so Windows-authored
264	// rule files don't silently slip past the warning.
265	func hasPathsFrontmatter(body []byte) bool {
266		rest, ok := stripFrontmatterOpener(body)
267		if !ok {
268			return false
269		}
270		// Look at the first non-blank line of the YAML block; reject if
271		// the first key is anything other than `paths`.
272		for {
273			nl := bytes.IndexByte(rest, '\n')
274			if nl < 0 {
275				return false
276			}
277			line := rest[:nl]
278			trim := bytes.TrimSpace(line)
279			if len(trim) == 0 {
280				rest = rest[nl+1:]
281				continue
282			}
283			return bytes.HasPrefix(trim, []byte("paths:"))
284		}
285	}
286	
287	// stripFrontmatterOpener returns the body bytes after a leading
288	// `---\n` or `---\r\n` separator. Returns ok=false when no opener is
289	// present.
290	func stripFrontmatterOpener(body []byte) ([]byte, bool) {
291		if bytes.HasPrefix(body, []byte("---\n")) {
292			return body[len("---\n"):], true
293		}
294		if bytes.HasPrefix(body, []byte("---\r\n")) {
295			return body[len("---\r\n"):], true
296		}
297		return nil, false
298	}
