14	func TestBundled_ManifestShape(t *testing.T) {
15		t.Parallel()
16	
17		b := Bundled()
18		if b == nil {
19			t.Fatal("Bundled returned nil")
20		}
21		if b.Run == nil {
22			t.Fatal("Bundled.Run is nil")
23		}
24	
25		if got, want := b.Manifest.Name, adapterName; got != want {
26			t.Errorf("Manifest.Name = %q, want %q", got, want)
27		}
28		if got, want := b.Manifest.ContractVersion, adapter.ContractVersionV1; got != want {
29			t.Errorf("Manifest.ContractVersion = %q, want %q", got, want)
30		}
31		if got, want := b.Manifest.ReservedPrefix, reservedPrefix; got != want {
32			t.Errorf("Manifest.ReservedPrefix = %q, want %q", got, want)
33		}
34		// Bundled adapters carry a placeholder Command so the shared
35		// adapter-manifest validator (which requires non-empty Command)
36		// accepts them at discovery time. The Run callback is what the
37		// runtime actually invokes; Command is diagnostic only.
38		if len(b.Manifest.Command) == 0 {
39			t.Error("Manifest.Command must not be empty (validator rejects empty Command even for bundled adapters)")
40		}
41	}
42	
43	func TestCapabilitiesYAML_MatchesCodeMap(t *testing.T) {
44		t.Parallel()
45	
46		d, err := loadDeclaration()
47		if err != nil {
48			t.Fatalf("loadDeclaration: %v", err)
49		}
50	
51		if got, want := d.Name, adapterName; got != want {
52			t.Errorf("declaration name=%q want %q", got, want)
53		}
54		if got, want := d.ContractVersion, adapter.ContractVersionV1; got != want {
55			t.Errorf("declaration contract_version=%q want %q", got, want)
56		}
57		if got, want := d.ReservedPrefix, reservedPrefix; got != want {
58			t.Errorf("declaration reserved_prefix=%q want %q", got, want)
