1	package claude
2	
3	import (
4		"context"
5		"encoding/json"
6		"errors"
7		"os"
8		"path/filepath"
9		"reflect"
10		"sort"
11		"strings"
12		"testing"
13	
14		"github.com/aienvs/aienvs/pkg/adapterkit"
15	)
16	
17	// emitFixture loads an IR document from testdata/ir and runs the
18	// production handleEmit (including its sort + dedup invariants) so
19	// the test path matches the wire path. Returns both the OpRecord
20	// summary and the raw Op list so tests can assert on op-specific
21	// fields (warning concept_id, write_tool_owned locator, content
22	// bytes) the OpRecord summary does not carry.
23	func emitFixture(t *testing.T, name string) (adapterkit.EmitResult, []adapterkit.Op) {
24		t.Helper()
25		raw, err := os.ReadFile(filepath.Join("testdata", "ir", name))
26		if err != nil {
27			t.Fatalf("read fixture %s: %v", name, err)
28		}
29		// Drive the same code path the wire-side runtime drives so the
30		// fixture-vs-wire assertion is meaningful. handleEmit owns the
31		// sort + dedup behavior; emitting via dispatchNode directly would
32		// silently bypass both and mask future regressions.
33		emitted, err := captureOps(raw)
34		if err != nil {
35			t.Fatalf("captureOps %s: %v", name, err)
36		}
37		return adapterkit.EmitResult{OpsPerformed: emitted.records()}, emitted.ops
38	}
39	
40	// captureOps replicates handleEmit's flow but returns the raw
41	// emittedOps so tests can inspect op-specific fields. Keeps test
42	// logic in one place rather than duplicating the sort + dedup
43	// across every fixture-driven test.
44	func captureOps(raw json.RawMessage) (*emittedOps, error) {
45		doc, err := decodeIRDocument(raw)
46		if err != nil {
47			return nil, err
48		}
49		if err := rejectDuplicateNodes(doc.Nodes); err != nil {
50			return nil, err
51		}
52		emitted := &emittedOps{}
53		state := &emitState{
54			readmeEmitted:   map[string]bool{},
55			sidecarEmitted:  false,
56			emittedFilePath: map[string]struct{}{},
57		}
58		sort.Slice(doc.Nodes, func(i, j int) bool {
59			if doc.Nodes[i].Kind != doc.Nodes[j].Kind {
60				return doc.Nodes[i].Kind < doc.Nodes[j].Kind
61			}
62			return doc.Nodes[i].ID < doc.Nodes[j].ID
63		})
64		for _, n := range doc.Nodes {
65			if !nodeTargetsClaude(n) {
66				continue
67			}
68			if err := dispatchNode(emitted, n, state); err != nil {
69				return nil, err
70			}
71		}
72		return emitted, nil
73	}
74	
75	func TestEmitRule_HappyPath(t *testing.T) {
76		t.Parallel()
77	
78		res, ops := emitFixture(t, "rule-only.json")
79	
80		wantRecords := []adapterkit.OpRecord{
81			{Op: adapterkit.OpKindMkdir, Path: ".claude/rules/aienvs"},
82			{Op: adapterkit.OpKindWriteFile, Path: ".claude/rules/aienvs/README.md"},
83			{Op: adapterkit.OpKindWriteFile, Path: ".claude/rules/aienvs/no-fri.md"},
84		}
85		if !reflect.DeepEqual(res.OpsPerformed, wantRecords) {
86			t.Fatalf("OpsPerformed mismatch:\n got: %+v\nwant: %+v", res.OpsPerformed, wantRecords)
