			for _, op := range res.OpsPerformed {
				if op.Op == adapterkit.OpKindWriteFile || op.Op == adapterkit.OpKindWriteToolOwned {
					t.Errorf("unsupported kind must not emit writes; got %+v", res.OpsPerformed)
